---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { readdir } from 'fs/promises';
import { join } from 'path';

// src/pages/news/ 폴더의 .astro 파일 목록
const newsDir = join(process.cwd(), 'src/pages/news');
const files = await readdir(newsDir);
const newsFiles = files
  .filter(f => f.endsWith('.astro') && f !== 'index.astro')
  .map(f => f.replace('.astro', ''))
  .sort((a, b) => b.localeCompare(a)); // 날짜 역순 정렬

// 수동으로 뉴스 메타데이터 정의 (나중에 자동화 가능)
const newsItems = newsFiles.map(slug => ({
  slug,
  title: '지난 24시간 세상의 모든 소식',
  date: new Date(slug), // 파일명이 날짜 형식이라고 가정
  subtitle: '증시, 정치, 국제, 기술, 과학, 스포츠 종합',
  categories: ['증시', 'AI', '정치', '국제', '과학', '스포츠'],
}));
---

<BaseLayout title="News">
  <h1>📰 Daily News</h1>
  <p class="description">
    지난 24시간 세상의 모든 소식 · 카라얀이 선별한 데일리 브리핑
  </p>

  <ul class="news-list">
    {newsItems.map(item => (
      <li>
        <a href={`/news/${item.slug}/`} class="news-card">
          <div class="news-header">
            <time datetime={item.date.toISOString()}>
              {item.date.toLocaleDateString('ko-KR', { 
                year: 'numeric', 
                month: 'long', 
                day: 'numeric',
                weekday: 'short'
              })}
            </time>
            {item.categories && (
              <div class="categories">
                {item.categories.map(cat => (
                  <span class="category-tag">{cat}</span>
                ))}
              </div>
            )}
          </div>
          <h2>{item.title}</h2>
          {item.subtitle && (
            <p class="subtitle">{item.subtitle}</p>
          )}
        </a>
      </li>
    ))}
  </ul>

  {newsItems.length === 0 && (
    <div class="empty-state">
      <p>아직 뉴스가 없습니다. 첫 번째 데일리 브리핑을 기다려주세요! 🎵</p>
    </div>
  )}
</BaseLayout>

<style>
  h1 {
    margin-bottom: 0.5rem;
  }

  .description {
    color: var(--text-secondary);
    font-size: 0.95rem;
    margin-bottom: 2rem;
  }

  .news-list {
    list-style: none;
    padding: 0;
    display: grid;
    gap: 1.5rem;
  }

  .news-card {
    display: block;
    padding: 1.5rem;
    border: 1px solid var(--border);
    border-radius: 12px;
    background: rgba(255, 255, 255, 0.6);
    transition: all 0.2s;
    text-decoration: none;
    color: inherit;
  }

  @supports (backdrop-filter: blur(8px)) {
    .news-card {
      backdrop-filter: blur(8px);
    }
  }

  .news-card:hover {
    border-color: var(--frog-green);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(91, 168, 71, 0.15);
  }

  .news-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.5rem;
  }

  time {
    font-size: 0.85rem;
    color: var(--text-secondary);
    font-weight: 500;
  }

  .categories {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
  }

  .category-tag {
    font-size: 0.75rem;
    padding: 2px 8px;
    border-radius: 4px;
    background: var(--frog-green);
    color: white;
    font-weight: 600;
  }

  .news-card h2 {
    font-size: 1.5rem;
    margin: 0 0 0.5rem 0;
    color: var(--dark-green);
  }

  .subtitle {
    font-size: 1rem;
    color: var(--text-secondary);
    font-style: italic;
    margin-bottom: 0.75rem;
  }

  .empty-state {
    text-align: center;
    padding: 4rem 2rem;
    color: var(--text-secondary);
  }

  @media (max-width: 640px) {
    .news-card {
      padding: 1rem;
    }

    .news-card h2 {
      font-size: 1.25rem;
    }
  }
</style>

